    <div class="stat-box">
      <div class="stat-number" data-target="10">0</div>
      <div class="stat-text">Team Members</div>
    </div>

    <div class="stat-box">
      <div class="stat-number" data-target="14">0</div>
      <div class="stat-text">Years of Experience</div>
    </div>

  </div>
</div>

<script>
  const counters = document.querySelectorAll('.stat-number');
  let started = false;

  const startCounting = () => {
    counters.forEach(counter => {
      const target = +counter.getAttribute('data-target');
      let count = 0;

      const increment = target / 60;

      const updateCount = () => {
        count += increment;
        if (count < target) {
          counter.innerText = Math.ceil(count) + "+";
          requestAnimationFrame(updateCount);
        } else {
          counter.innerText = target + "+";
        }
      };

      updateCount();
    });
  };

  // 👀 Trigger animation when visible
  const observer = new IntersectionObserver(entries => {
    if (entries[0].isIntersecting && !started) {
      startCounting();
      started = true;
    }
  });

  observer.observe(document.querySelector('.stats-section'));
</script>","originalElement":"__raw_html__","activeState":null,"dynamicValues":[],"customAttributes":{}}],"baseStyles":{"display":"flex","flexDirection":"column","flexShrink":0,"overflow":"hidden","position":"static","width":"100%","justifyContent":"flex-start","alignItems":"center"},"rawStyles":{},"mobileStyles":{},"tabletStyles":{},"attributes":{},"classes":[],"dataKey":null,"blockName":"container","element":"div","activeState":null,"dynamicValues":[],"customAttributes":{}},{"blockId":"mu0b4i1fu","children":[{"blockId":"wsjvctdyg","children":[],"baseStyles":{"height":"fit-content","width":"fit-content"},"rawStyles":{},"mobileStyles":{},"tabletStyles":{},"attributes":{},"classes":[],"dataKey":null,"blockName":"Embed HTML","element":"div","innerHTML":"<link href="https://fonts.googleapis.com/css2?family=Poppins:wght@500;600&display=swap" rel="stylesheet">

