const startCounter = (counter) => {
    const target = +counter.getAttribute('data-target');
    let count = 0;
    const speed = target / 50;

    const update = () => {
        count += speed;
        if (count < target) {
            counter.innerText = Math.ceil(count) + "+";
            requestAnimationFrame(update);
        } else {
            counter.innerText = target + "+";
        }
    };

    update();
};

// Trigger on scroll
