<style>
.blog-section {
    font-family: 'Inter', sans-serif;
    padding: 70px 20px;
}

.blog-container {
    max-width: 1250px;
    margin: auto;
    display: flex;
    gap: 50px;
    align-items: center;
}

/* LEFT */
.blog-left {
    flex: 1;
}

.blog-title {
    font-weight: 700;
    color: #353F4F;
    margin-bottom: 40px;
    font-family: 'Poppins';
    font-size: 54px;
    line-height: 42.89px;
    letter-spacing: -0.48px;
    /*text-align: center;*/
    vertical-align: middle;
}

.blog-desc {
    color: #353F4F;
    max-width: 409px;
    font-family: 'Poppins';
    font-weight: 400;
    font-size: 24px;
    line-height: 30px;
}

/* VIEW BUTTON */
.view-btn {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 6px 14px 6px 6px;
    background: #FFFFFF;
    border-radius: 50px;
    text-decoration: none;
    margin-top: 58px;
    border: 1px solid #D9D9D9
}

.view-btn:hover {
    background: #e5e7eb;
}

/*.view-btn .icon-circle {*/
/*    width: 24px;*/
/*    height: 24px;*/
/*    background: #7ed957;*/
/*    border-radius: 50%;*/
/*    display: flex;*/
/*    align-items: center;*/
/*    justify-content: center;*/
/*}*/

.view-btn .icon-circle img {
    width: 30px;
    height: 30px;
    /*filter: brightness(0) invert(1);*/
}

.view-btn .text {
    color: #353F4F;
    font-family: 'Poppins';
    font-weight: 600;
    font-size: 16px;
}

/* ARROWS */
.arrow-controls {
    display: flex;
    gap: 12px;
    margin-top: 22px;
}

.arrow {
    width: 36.35px;
    height: 36.35px;
    border-radius: 50%;
    border: 1px solid #d1d5db;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #fff;
    cursor: pointer;
    box-shadow: 0px 4px 4px 0px #D9D9D940;
    box-shadow: 4px 0px 4px 0px #D9D9D947;
}

.arrow img {
    width: 17.87631356538301px;
    color: #353F4F;
}

.arrow.active {
    background: #78B526;
    border: none;
}

.arrow.active img {
    filter: brightness(0) invert(1);
}

/* RIGHT → ONLY 2 CARDS VISIBLE */
.blog-right {
    flex: none;
    width: 710px; /* 🔥 key fix */
    overflow: hidden;
}

/* TRACK */
.blog-track {
    display: flex;
    gap: 20px;
    transition: transform 0.4s ease;
}

/* CARD */
.blog-card {
    min-width: 341px;
    background: #fff;
    border-radius: 10px;
    overflow: hidden;
    /*box-shadow: 0 6px 16px rgba(0,0,0,0.08);*/
    box-shadow: 0px 4px 4px 0px #6C757D40;
    box-shadow: 4px 0px 4px 0px #6C757D40;
}

.blog-img {
    width: 100%;
    height: 246px;
    object-fit: cover;
}

.blog-content {
    padding: 16px;
}

.blog-heading {
    color: #353F4F;
    margin-bottom: 6px;
    font-family: 'Poppins';
    font-weight: 700;
    font-size: 13.42px;
    line-height: 132%;
    letter-spacing: 4%;
}

.blog-text {
    color: #6C757D;
    margin-bottom: 10px;
    font-family: 'Poppins';
    font-weight: 400;
    font-size: 11.99px;
    line-height: 170%;
    letter-spacing: 4%;
}

.read-more {
    color: #353F4F;
    text-decoration: none;
    font-family: 'Poppins';
    font-weight: 600;
    font-size: 14.99px;
    line-height: 98%;
}

.read-more::after {
    content: " →";
}

/* =========================
   MOBILE RESPONSIVE FIX
   ========================= */
@media (max-width: 768px) {

    .blog-section {
        padding: 40px 15px;
    }

    .blog-container {
        flex-direction: column;
        gap: 25px;
    }

    .blog-title {
        font-size: 28px;
        line-height: 36px;
        margin-bottom: 15px;
    }

    .blog-desc {
        font-size: 15px;
        line-height: 24px;
        max-width: 100%;
    }

    .view-btn {
        margin-top: 20px;
    }

    /* ✅ SHOW ARROWS */
    .arrow-controls {
        display: flex;
        margin-top: 15px;
    }

    .blog-right {
        width: 100%;
        overflow: hidden;
    }

    .blog-track {
        gap: 15px;
        padding-right: 20px;   /* 🔥 next card visible */
    }

    .blog-card {
        min-width: 78%;        /* 🔥 key fix */
    }

    .blog-img {
        height: 180px;
    }

}

/* =========================
   EXTRA SMALL DEVICES
   ========================= */
@media (max-width: 480px) {

    .blog-title {
        font-size: 24px;
        line-height: 32px;
    }

    .blog-desc {
        font-size: 14px;
    }

    .blog-card {
        min-width: 90%;
    }

    .blog-img {
        height: 160px;
    }

}
</style>

